def _release_status(row: dict[str, Any]) -> str:
    status, readiness = _s(row.get("acceptance_status")), _s(row.get("acceptance_readiness"))
    if readiness == "FAIL_CLOSED" or status == "CLEARANCE_ACCEPTANCE_BLOCKED" or row.get("blocked"): return "CLEARANCE_RELEASE_BLOCKED"
    if status == "CLEARANCE_ACCEPTANCE_WAITING_EXTERNAL_ARTIFACT" or row.get("requires_external_artifact"): return "CLEARANCE_RELEASE_WAITING_EXTERNAL_ARTIFACT"
    if status in {"CLEARANCE_ACCEPTANCE_WAITING_REFRESH", "CLEARANCE_ACCEPTANCE_WAITING_AUTHORIZED_REVIEW"} or row.get("waiting") or row.get("requires_authorized_review"): return "CLEARANCE_RELEASE_WAITING_ACCEPTANCE"
    if status == "CLEARANCE_ACCEPTANCE_READY_FOR_OBSERVATION" or row.get("ready_for_acceptance_observation"): return "CLEARANCE_RELEASE_READY_FOR_OBSERVATION"
    return "CLEARANCE_RELEASE_INVESTIGATION_REQUIRED"

def _release_readiness(status: str) -> str: return "FAIL_CLOSED" if status == "CLEARANCE_RELEASE_BLOCKED" else "RELEASE_READY_OBSERVATION" if status == "CLEARANCE_RELEASE_READY_FOR_OBSERVATION" else "WAITING"

def _release_gate(status: str) -> str: return {"CLEARANCE_RELEASE_BLOCKED": "source_acceptance_card_stops_clearance_release_observation", "CLEARANCE_RELEASE_WAITING_EXTERNAL_ARTIFACT": "external_artifacts_present_before_clearance_release_review", "CLEARANCE_RELEASE_WAITING_ACCEPTANCE": "source_clearance_acceptance_observed_before_release_readiness_review", "CLEARANCE_RELEASE_INVESTIGATION_REQUIRED": "acceptance_card_status_reclassified_to_known_release_terminal_state", "CLEARANCE_RELEASE_READY_FOR_OBSERVATION": "authorized_human_may_release_clearance_outside_this_read_plane_after_acceptance_review"}.get(status, "source_acceptance_card_resolved_or_reclassified")

def _release_instruction(status: str, lane: str) -> str:
    if status == "CLEARANCE_RELEASE_BLOCKED": return f"{lane} remains fail-closed in the acceptance board; do not release clearance until upstream blockers are resolved."
    if status == "CLEARANCE_RELEASE_WAITING_EXTERNAL_ARTIFACT": return f"{lane} is waiting on external artifacts; release readiness must stay observational until governed evidence arrives."
    if status == "CLEARANCE_RELEASE_WAITING_ACCEPTANCE": return f"{lane} still needs acceptance observation, authorized review, or refresh before release readiness can be trusted."
    if status == "CLEARANCE_RELEASE_READY_FOR_OBSERVATION": return f"{lane} is only observed as ready for clearance release review; this read-plane writes no release, acceptance, signoff, approval, decision, or record."
    return f"{lane} requires investigation because the acceptance card is not classified enough for release-readiness routing."

