def _sort_card(row: dict[str, Any]) -> tuple[Any, ...]: return (int(row.get("release_status_rank") if row.get("release_status_rank") is not None else 99), int(row.get("release_readiness_rank") if row.get("release_readiness_rank") is not None else 99), _PRIORITY_RANK.get(_norm(row.get("priority")), 9), _SEVERITY_RANK.get(_norm(row.get("severity")), 9), _s(row.get("evidence_lane")))

def _haystack(row: dict[str, Any]) -> str: return "\n".join(_s(row.get(key)) for key in ("release_readiness_card_id", "evidence_lane", "release_status", "release_readiness", "source_acceptance_status", "source_acceptance_readiness", "source_signoff_status", "priority", "severity", "trust_banner", "owner_hint", "release_gate", "release_instruction", "summary_line"))

def _matches(row: dict[str, Any], *, experiment_id_contains: str | None, issue_contains: str | None, evidence_lane: set[str], release_status: set[str], release_readiness: set[str], acceptance_status: set[str], acceptance_readiness: set[str], signoff_status: set[str], signoff_readiness: set[str], docket_status: set[str], closeout_status: set[str], priority: set[str], severity: set[str], trust_banner: set[str], owner_hint: set[str], ready_for_release_observation: bool | None, blocked: bool | None, waiting: bool | None, requires_acceptance_observation: bool | None, requires_external_artifact: bool | None) -> bool:
    owner_values = {_norm(value) for value in _as_list(row.get("owner_hints"))}
    return (_contains("\n".join(_as_list(row.get("experiment_ids"))), experiment_id_contains) and _contains(_haystack(row) + "\n" + "\n".join(_as_list(row.get("issue_codes"))), issue_contains) and (not evidence_lane or _norm(row.get("evidence_lane")) in evidence_lane) and (not release_status or _norm(row.get("release_status")) in release_status) and (not release_readiness or _norm(row.get("release_readiness")) in release_readiness) and (not acceptance_status or _norm(row.get("source_acceptance_status")) in acceptance_status) and (not acceptance_readiness or _norm(row.get("source_acceptance_readiness")) in acceptance_readiness) and (not signoff_status or _norm(row.get("source_signoff_status")) in signoff_status) and (not signoff_readiness or _norm(row.get("source_signoff_readiness")) in signoff_readiness) and (not docket_status or _norm(row.get("source_docket_status")) in docket_status) and (not closeout_status or _norm(row.get("source_closeout_status")) in closeout_status) and (not priority or _norm(row.get("priority")) in priority) and (not severity or _norm(row.get("severity")) in severity) and (not trust_banner or _norm(row.get("trust_banner")) in trust_banner) and (not owner_hint or bool(owner_values & owner_hint) or _norm(row.get("owner_hint")) in owner_hint) and (ready_for_release_observation is None or bool(row.get("ready_for_release_observation")) is ready_for_release_observation) and (blocked is None or bool(row.get("blocked")) is blocked) and (waiting is None or bool(row.get("waiting")) is waiting) and (requires_acceptance_observation is None or bool(row.get("requires_acceptance_observation")) is requires_acceptance_observation) and (requires_external_artifact is None or bool(row.get("requires_external_artifact")) is requires_external_artifact))

def _degraded(source_payload: dict[str, Any], rows: list[dict[str, Any]]) -> list[str]:
    degraded = [f"SOURCE_CLEARANCE_ACCEPTANCE_BOARD::{item}" for item in _as_list(source_payload.get("degraded"))]
    if any(row.get("release_readiness") == "FAIL_CLOSED" for row in rows): degraded.append("SEMANTIC_VALIDATOR_HANDOFF_CLEARANCE_RELEASE_READINESS_BOARD_FAIL_CLOSED_PRESENT")
    if any(row.get("release_status") == "CLEARANCE_RELEASE_WAITING_EXTERNAL_ARTIFACT" for row in rows): degraded.append("SEMANTIC_VALIDATOR_HANDOFF_CLEARANCE_RELEASE_READINESS_BOARD_EXTERNAL_ARTIFACT_WAITING")
    if any(row.get("release_status") == "CLEARANCE_RELEASE_WAITING_ACCEPTANCE" for row in rows): degraded.append("SEMANTIC_VALIDATOR_HANDOFF_CLEARANCE_RELEASE_READINESS_BOARD_ACCEPTANCE_WAITING")
    if any(row.get("release_status") == "CLEARANCE_RELEASE_INVESTIGATION_REQUIRED" for row in rows): degraded.append("SEMANTIC_VALIDATOR_HANDOFF_CLEARANCE_RELEASE_READINESS_BOARD_INVESTIGATION_REQUIRED")
    return sorted(set(degraded))
